select 
distinct(variant_get(meta, "$." || {UC_SCHEMA}.retrieve_dicom_tag('patient id').TAG || '.Value[0]', 'STRING')) as PATIENT_ID,
  TRY_CAST(
    REPLACE(
      variant_get(meta, "$." || {UC_SCHEMA}.retrieve_dicom_tag('patient age').TAG || '.Value[0]' , 'STRING'),
      "Y",
      ""
    ) AS INTEGER
  ) AS patient_age
from {UC_SCHEMA}.object_catalog;
